      },
      {
        "rule": "Delivery is successful if and only if the subscriber responds with an HTTP 2xx status within 5 seconds.",
        "testable_assertion": "A response of 200, 201, or 204 within 5s results in status 'delivered'. A response of 301, 400, 503, or any non-2xx results in status 'failed'. No response within 5s results in status 'failed'."
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Single service: WebhookDeliveryService with method deliver(event, subscriberUrl) returning DeliveryResult.",
